/// Subcommands of `laverna corpus`.
#[derive(Subcommand)]
enum CorpusAction {
    /// Write the embedded corpus to <dir>/formulas.toml and <dir>/entities.toml
    Export {
        /// Output directory (created if missing)
        dir: String,
        /// Output format. `toml` (default) writes formulas.toml/entities.toml/
        /// version.toml. `cid-facts` additionally emits cid_facts.json — a
        /// fact-source file consumable by Ł.AI · Gate (CID) as a fact gate.
        #[arg(long, value_name = "FMT", default_value = "toml")]
        format: String,
    },
    /// Validate the corpus (embedded, or from <dir> if given) — checks Tanto
    /// parsability, graha references, non-empty descriptions, duplicate ids.
    Validate {
        /// Optional directory containing formulas.toml / entities.toml to validate
        dir: Option<String>,
    },
    /// Diff two exported corpus directories (added / removed / changed).
    Diff {
        /// First corpus directory
        a: String,
        /// Second corpus directory
        b: String,
    },
    /// Emit a DOT graph of formula inputs→output dependencies to stdout.
    Graph {
        /// Optional directory containing formulas.toml to graph
        dir: Option<String>,
    },
    /// Lint the corpus (embedded, or from <dir> if given) — deeper checks than
    /// `validate`: flags expressions that reference undeclared variables and
    /// formulas missing a graha/zodiac tag. Warnings are non-fatal.
    Lint {
        /// Optional directory containing formulas.toml / entities.toml to lint
        dir: Option<String>,
    },
    /// Print the embedded corpus version (semver) and content hash. The hash
    /// lets community forks / CI detect corpus drift independent of the binary.
    Hash,
}

/// Subcommands of `lai gate`.
#[derive(Subcommand)]
enum GateAction {
    /// Validate a response (tokens or full text) against a context
    Validate {
        /// Response text to validate
        text: String,
        /// Context (original prompt/query)
        context: String,
        /// Domain for fact-checking (e.g., "math", "astronomy")
        domain: Option<String>,
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
    },
    /// Auto-fix a failing response (append verdict, replace bare numbers)
    Fix {
        /// Failing response text
        text: String,
        /// Context (original prompt/query)
        context: String,
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
    },
    /// Compress a prompt to a target token budget
    Compress {
        /// Prompt text to compress
        text: String,
        /// Compression level: light, medium, aggressive (default: light)
        level: Option<String>,
    },
    /// Score a response on a 0-100 scale
    Score {
        /// Response text to score
        text: String,
        /// Optional context (original prompt/query)
        context: Option<String>,
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
    },
    /// Start Gate MCP server on stdin/stdout
    Mcp,
    /// Start Gate HTTP MCP server on a port
    McpHttp {
        /// Address to bind (default: 127.0.0.1:3000)
        addr: Option<String>,
    },
    /// Start Gate proxy server (LLM passthrough with validation)
    Proxy {
        /// Port to listen on
        port: u16,
        /// LLM backend URL
        #[arg(long)]
        llm: String,
        /// API key for the LLM
        #[arg(long)]
        key: String,
    },
}

/// Subcommands of `lai tanto`.
