// ─── Feature Detection ──────────────────────────────────────────────────────

fn collect_features() -> &'static str {
    let mut features = Vec::new();
    if cfg!(feature = "mcp") {
        features.push("mcp");
    }
    if cfg!(feature = "websearch") {
        features.push("websearch");
    }
    if cfg!(feature = "budget") {
        features.push("budget");
    }
    if cfg!(feature = "llm") {
        features.push("llm");
    }
    // Seed corpus is always embedded in the binary (T35) — surfaced for transparency.
    features.push("embedded-corpus");
    if !corpus_overlay_dirs().is_empty() {
        features.push("corpus-overlay");
    }
    if cfg!(feature = "bench") {
        features.push("bench");
    }
    if features.is_empty() {
        "none (minimal)"
    } else {
        Box::leak(features.join(", ").into_boxed_str())
    }
}

// ─── Data Loading ───────────────────────────────────────────────────────────
//
// The seed corpus (formulas, synonyms, entities, nonmath, shikai forms, events)
// is compiled into the binary by `build.rs` (embedded.rs) and loaded here. This
// makes the binary self-contained: it returns the full corpus from any working
// directory, fixing T35 (entities/formulas previously only loaded when run from
// the repo root).

fn load_formula_registry() -> FormulaRegistry {
    let mut reg = FormulaRegistry::new();
    // Embedded `[[formula]]` corpus + search synonyms. NONMATH_TOML holds
    // `[[grammar]]` tables, which the formula registry ignores (harmless no-op
    // here, but keeps the embedded corpus available should grammar support land).
    reg.load_from_toml_str(FORMULAS_TOML)
        .expect("embedded FORMULAS_TOML must parse");
    reg.load_synonyms_from_str(SYNONYMS_TOML)
        .expect("embedded SYNONYMS_TOML must parse");
    reg.load_from_toml_str(NONMATH_TOML)
        .expect("embedded NONMATH_TOML must parse");
    // Overlay corpus (`~/.laverna/corpus`, `./corpus`) merges over the seed —
    // same-id formulas override. Files with no `[[formula]]` table are ignored.
    // Best-effort: a malformed overlay file is skipped, not fatal.
    for c in corpus_overlay_toml_contents() {
        let _ = reg.load_from_toml_str(&c);
    }
    reg
}

fn load_entity_registry() -> EntityRegistry {
    let mut reg = EntityRegistry::new();
    reg.load_seeds_from_str(ENTITIES_TOML)
        .expect("embedded ENTITIES_TOML must parse");
    // Overlay entities merge over the seed corpus; files with no `[[entity]]`
    // table are ignored. Best-effort: malformed overlay files are skipped.
    for c in corpus_overlay_toml_contents() {
        let _ = reg.load_seeds_from_str(&c);
    }
    reg
}

fn load_shikai_forms() -> ShikaiFormRegistry {
    let mut forms = ShikaiFormRegistry::new();
    forms
        .load_from_str(SHIKAI_FORM_TOML)
        .expect("embedded SHIKAI_FORM_TOML must parse");
    forms
}

fn load_events() -> EventRegistry {
    let mut events = EventRegistry::new();
    let _ = events.load_from_str(EVENTS_TOML);
    events
}

fn load_athena_registries() -> (AthenaFormulaRegistry, AthenaEntityRegistry) {
    let mut formula_reg = AthenaFormulaRegistry::new();
    formula_reg
        .load_from_toml_str(ATHENA_FORMULAS_TOML)
        .expect("embedded ATHENA_FORMULAS_TOML must parse");
    formula_reg.rebuild_tfidf();

    let mut entity_reg = AthenaEntityRegistry::new();
    entity_reg
        .load_seeds_from_str(ATHENA_ENTITIES_TOML, None)
        .expect("embedded ATHENA_ENTITIES_TOML must parse");

    (formula_reg, entity_reg)
}

// ─── solve Command ──────────────────────────────────────────────────────────

/// Extract the longest contiguous arithmetic expression from a query, keeping
/// its operators so it can be evaluated with operator precedence (via the Tanto
/// parser `validate` uses) instead of naive pairwise number addition (T36).
/// Returns `None` when no numeric/operator run is present.
fn extract_arithmetic_expression(query: &str) -> Option<String> {
    let bytes = query.as_bytes();
    let is_op_char = |b: u8| {
        b.is_ascii_digit()
            || b == b'.'
            || matches!(
                b,
                b'+' | b'-' | b'*' | b'/' | b'%' | b'^' | b'(' | b')' | b'='
            )
            || b.is_ascii_whitespace()
    };
    let mut best_start: Option<usize> = None;
    let mut best_end: usize = 0;
    let mut best_len: usize = 0;
    let mut start: Option<usize> = None;
    let mut end_run = |s: usize, e: usize| {
        let len = e - s;
        if len > best_len {
            best_len = len;
            best_start = Some(s);
            best_end = e;
        }
    };
    for (i, &b) in bytes.iter().enumerate() {
        if is_op_char(b) {
            if start.is_none() {
                start = Some(i);
            }
        } else if let Some(s) = start.take() {
            end_run(s, i);
        }
    }
    if let Some(s) = start.take() {
        end_run(s, bytes.len());
    }
    best_start
        .map(|s| {
            let mut expr: String = query[s..best_end].trim().to_string();
            while matches!(
                expr.bytes().last(),
                Some(b'+' | b'*' | b'/' | b'%' | b'^' | b'=')
            ) {
                expr.pop();
            }
            while matches!(expr.bytes().next(), Some(b'+' | b'*' | b'/' | b'%' | b'=')) {
                expr.remove(0);
            }
            expr
        })
        .filter(|e| !e.is_empty() && e.chars().any(|c| c.is_ascii_digit()))
}

/// A single operator-expression evaluation result for JSON/text output.
struct NumExpr {
    expr: String,
    lhs_value: Option<f64>,
    stated_rhs: Option<f64>,
    matches: Option<bool>,
}

/// Fully-computed `solve` result — rendered as text or JSON without recomputation.
struct SolveResult {
    query: String,
    intent: &'static str,
    domain: &'static str,
    numerical: Vec<f64>,
    matrix: SettlingMatrix,
    tanto_evals: Vec<(String, String, Option<f64>)>,
    num_exprs: Vec<NumExpr>,
    provenance: Vec<(String, Vec<ProvenanceStep>)>,
}

/// Run the full `solve` pipeline and collect every result field.
fn run_solve(query: &str) -> SolveResult {
    let formula_reg = load_formula_registry();
    let entity_reg = load_entity_registry();
    let forms = load_shikai_forms();
    let events = load_events();

    let descent_engine = DescentEngine::new(formula_reg.clone(), entity_reg.clone(), forms, events);

    let intent = parse_query_intent(query);
    let domain = determine_query_domain(query);
    let numerical = extract_numerical_values(query);

    let matrix = descent_engine.descend(query);

    let env = create_env();
    let mut tanto_evals = Vec::new();
    for token in &matrix.tokens {
        if let Some(ref expr) = token.formal_expression {
            let val = evaluate_expr(expr, &env);
            tanto_evals.push((token.text.clone(), expr.clone(), val));
        }
    }

    let mut num_exprs = Vec::new();
    if numerical.len() >= 2 {
        if let Some(expr) = extract_arithmetic_expression(query) {
            if let Some(eq_pos) = expr.find('=') {
                let left_operand = expr[..eq_pos].trim();
                let right_operand = expr[eq_pos + 1..].trim();
                match (
                    evaluate_expr(left_operand, &env),
                    right_operand.parse::<f64>().ok(),
                ) {
                    (Some(l_val), Some(r_val)) => {
                        let matches = (l_val - r_val).abs() < 1e-9;
                        num_exprs.push(NumExpr {
                            expr: expr.clone(),
                            lhs_value: Some(l_val),
                            stated_rhs: Some(r_val),
                            matches: Some(matches),
                        });
                    }
                    (Some(l_val), None) => num_exprs.push(NumExpr {
                        expr: expr.clone(),
                        lhs_value: Some(l_val),
                        stated_rhs: None,
                        matches: None,
                    }),
                    _ => num_exprs.push(NumExpr {
                        expr: expr.clone(),
                        lhs_value: None,
                        stated_rhs: None,
                        matches: None,
                    }),
                }
            } else if let Some(val) = evaluate_expr(&expr, &env) {
                num_exprs.push(NumExpr {
                    expr: expr.clone(),
                    lhs_value: Some(val),
                    stated_rhs: None,
                    matches: None,
                });
            } else {
                num_exprs.push(NumExpr {
                    expr: expr.clone(),
                    lhs_value: None,
                    stated_rhs: None,
                    matches: None,
                });
            }
        }
    }

    let provenance = matrix
        .tokens
        .iter()
        .filter(|t| !t.provenance.is_empty())
        .map(|t| (t.text.clone(), t.provenance.clone()))
        .collect();

    SolveResult {
        query: query.to_string(),
        intent,
        domain,
        numerical,
        matrix,
        tanto_evals,
        num_exprs,
        provenance,
    }
}

/// Build the *hashed payload* of a proof object: every provable field, with no
/// `digest` and no wall-clock `computed_at` (T52/T53). Keys serialize in a
/// canonical, sorted order because `serde_json::Value` is backed by a `BTreeMap`
/// (no `preserve_order` feature), so the same result always yields identical
/// bytes — the precondition for a content digest to mean anything.
fn build_proof_payload(result: &SolveResult) -> serde_json::Value {
    let tokens: Vec<serde_json::Value> = result
        .matrix
        .tokens
        .iter()
        .map(|t| {
            serde_json::json!({
                "text": t.text,
                "settled_layer": t.settled_layer.name(),
                "depth": t.settled_layer.depth(),
                // `domains` serializes in a stable sorted-by-name order via the
                // `SettledToken` custom serializer, so emitted order is
                // deterministic across runs (verify is recomputation, not an
                // echo). The in-memory `t.domains` order is untouched, so
                // `domains[0]` (dominant_graha) semantics are unaffected.
                "domains": t.domains.iter().map(|d| d.name()).collect::<Vec<_>>(),
                "formulas": t.formulas,
                "entity": t.entity,
                "is_absolute": t.is_absolute,
                "confidence": t.confidence
            })
        })
        .collect();

    let tanto_evaluations: Vec<serde_json::Value> = result
        .tanto_evals
        .iter()
        .map(|(text, expr, val)| {
            serde_json::json!({
                "token": text,
                "expression": expr,
                "value": val
            })
        })
        .collect();

    serde_json::json!({
        "schema_version": "1.1.0",
        "query": result.query,
        "laverna_version": env!("CARGO_PKG_VERSION"),
        "corpus": {
            "version": CORPUS_VERSION,
            "content_hash": CORPUS_CONTENT_HASH
        },
        "descent": {
            "resolution_score": result.matrix.resolution_score * 100.0,
            "average_depth": result.matrix.average_depth,
            "layer_counts": result.matrix.layer_counts,
            "nand_completeness": result.matrix.tokens.iter().filter(|t| t.is_absolute).count() as f64
                / result.matrix.tokens.len().max(1) as f64,
            "tokens": tokens
        },
        "tanto_evaluations": tanto_evaluations,
        "dominant_domains": result.matrix.dominant_domains.iter().map(|d| d.name()).collect::<Vec<_>>(),
        "intent": result.intent,
        "domain": result.domain
    })
}

/// Content digest over a canonicalized proof payload (T52). SHA-256 of the
/// sorted-key JSON serialization; the payload never contains `digest` or
/// `computed_at`, so the digest is byte-reproducible across runs and machines.
fn proof_digest(payload: &serde_json::Value) -> String {
    let canonical = serde_json::to_string(payload).unwrap_or_default();
    laverna::digest::sha256_hex(canonical.as_bytes())
}

/// Build a complete, machine-verifiable proof object from a `solve` result.
///
/// The object is the hashed payload plus a `digest` (SHA-256 over the canonical
/// payload). `computed_at` is an *envelope* field outside the digest and is only
/// emitted when `include_timestamp` is set — off by default so proofs are
/// byte-reproducible (T53).
fn build_proof_object(result: &SolveResult, include_timestamp: bool) -> serde_json::Value {
    let payload = build_proof_payload(result);
    let digest = proof_digest(&payload);

    let mut proof = payload;
    if let Some(map) = proof.as_object_mut() {
        map.insert(
            "digest".to_string(),
            serde_json::json!({ "algorithm": "sha256", "value": digest }),
        );
        if include_timestamp {
            map.insert(
                "computed_at".to_string(),
                serde_json::Value::String(chrono_now()),
            );
        }
    }
    proof
}

/// Strip the non-hashed envelope fields (`digest`, `computed_at`) from a proof,
/// leaving the canonical payload that the digest is computed over.
fn proof_payload_view(proof: &serde_json::Value) -> serde_json::Value {
    let mut payload = proof.clone();
    if let Some(map) = payload.as_object_mut() {
        map.remove("digest");
        map.remove("computed_at");
    }
    payload
}

/// Re-verify a proof object emitted by `solve --proof-out` (T52).
///
/// Verification is *recomputation*, not echoing: the descent is re-run from the
/// recorded `query` against the embedded corpus, and the resulting canonical
/// payload must be byte-identical to the recorded one. Any divergence — a
/// tampered query, mutated scores, forged tokens — fails loud with a non-zero
/// exit. The recorded `digest` is also checked for internal consistency.
fn cmd_verify(path: &str, format: OutputFormat) {
    let body = match std::fs::read_to_string(path) {
        Ok(b) => b,
        Err(e) => {
            eprintln!("error: cannot read proof '{path}': {e}");
            std::process::exit(2);
        }
    };
    let proof: serde_json::Value = match serde_json::from_str(&body) {
        Ok(v) => v,
        Err(e) => {
            eprintln!("error: proof is not valid JSON: {e}");
            std::process::exit(2);
        }
    };

    let query = proof["query"].as_str().unwrap_or("").to_string();
    let recorded_payload = proof_payload_view(&proof);

    // 1. Digest integrity: does the recorded digest match the recorded payload?
    let recorded_digest = proof["digest"]["value"].as_str().unwrap_or("");
    let recomputed_digest_of_recorded = proof_digest(&recorded_payload);
    let digest_ok = !recorded_digest.is_empty() && recorded_digest == recomputed_digest_of_recorded;

    // 2. Recomputation: re-run the descent and rebuild the canonical payload.
    let recomputed_payload = build_proof_payload(&run_solve(&query));
    let recomputed_digest = proof_digest(&recomputed_payload);
    let recompute_ok = recorded_payload == recomputed_payload;

    // Field-level divergences for the report.
    let mismatches = payload_field_mismatches(&recorded_payload, &recomputed_payload);

    let verified = digest_ok && recompute_ok;

    if format == OutputFormat::Json {
        let out = serde_json::json!({
            "verified": verified,
            "query": query,
            "digest_ok": digest_ok,
            "recompute_ok": recompute_ok,
            "recorded_digest": recorded_digest,
            "recomputed_digest": recomputed_digest,
            "schema_version": proof["schema_version"].as_str().unwrap_or("?"),
            "laverna_version": proof["laverna_version"].as_str().unwrap_or("?"),
            "corpus_version": proof["corpus"]["version"].as_str().unwrap_or("?"),
            "corpus_content_hash": proof["corpus"]["content_hash"].as_str().unwrap_or("?"),
            "mismatched_fields": mismatches,
        });
        println!("{}", serde_json::to_string(&out).unwrap());
    } else {
        println!("  Query: {query:?}");
        println!(
            "  Corpus: v{} (content_hash {})",
            proof["corpus"]["version"].as_str().unwrap_or("?"),
            proof["corpus"]["content_hash"].as_str().unwrap_or("?"),
        );
        println!(
            "  {} Digest integrity (recorded matches payload)",
            if digest_ok { "✓" } else { "✗" }
        );
        if !digest_ok {
            println!("      recorded:   {recorded_digest}");
            println!("      recomputed: {recomputed_digest_of_recorded}");
        }
        println!(
            "  {} Recomputation (descent re-run matches recorded claim)",
            if recompute_ok { "✓" } else { "✗" }
        );
        if !recompute_ok {
            for field in &mismatches {
                println!("      ✗ diverges: {field}");
            }
        }
        println!();
        if verified {
            println!(
                "✓ Proof object VERIFIED (schema {})",
                proof["schema_version"].as_str().unwrap_or("?")
            );
        } else {
            println!("✗ Proof object REJECTED — recomputation does not match the recorded claim");
        }
    }

    if !verified {
        std::process::exit(1);
    }
}

/// Report the top-level payload fields that differ between a recorded proof and
/// a freshly recomputed one. Descends one level into `descent` for precision.
fn payload_field_mismatches(
    recorded: &serde_json::Value,
    recomputed: &serde_json::Value,
) -> Vec<String> {
    let mut out = Vec::new();
    let empty = serde_json::Map::new();
    let rec = recorded.as_object().unwrap_or(&empty);
    let fresh = recomputed.as_object().unwrap_or(&empty);

    let mut keys: Vec<&String> = rec.keys().chain(fresh.keys()).collect();
    keys.sort();
    keys.dedup();

    for key in keys {
        let a = rec.get(key);
        let b = fresh.get(key);
        if a == b {
            continue;
        }
        if key == "descent" {
            let da = a.and_then(|v| v.as_object()).unwrap_or(&empty);
            let db = b.and_then(|v| v.as_object()).unwrap_or(&empty);
            let mut dk: Vec<&String> = da.keys().chain(db.keys()).collect();
            dk.sort();
            dk.dedup();
            for k in dk {
                if da.get(k) != db.get(k) {
                    out.push(format!("descent.{k}"));
                }
            }
        } else {
            out.push(key.clone());
        }
    }
    out
}

/// Resolve the formulas corpus TOML: from `<dir>/formulas.toml` if present,
/// otherwise the embedded `FORMULAS_TOML` + `NONMATH_TOML`.
fn corpus_formulas_toml(dir: Option<&str>) -> String {
    if let Some(d) = dir {
        let path = std::path::Path::new(d).join("formulas.toml");
        if let Ok(c) = std::fs::read_to_string(&path) {
            return c;
        }
    }
    let mut s = String::new();
    s.push_str(FORMULAS_TOML);
    s.push('\n');
    s.push_str(NONMATH_TOML);
    s
}

/// Resolve the entities corpus TOML: from `<dir>/entities.toml` if present,
/// otherwise the embedded `ENTITIES_TOML`.
fn corpus_entities_toml(dir: Option<&str>) -> String {
    if let Some(d) = dir {
        let path = std::path::Path::new(d).join("entities.toml");
        if let Ok(c) = std::fs::read_to_string(&path) {
            return c;
        }
    }
    ENTITIES_TOML.to_string()
}

/// Overlay corpus directories (community-extension surface, §12.2). Files
/// dropped here are merged over the embedded seed corpus — a formula/entity
/// with the same id overrides the seed entry. Returned in a fixed order
/// (user home first, then CWD) so resolution is deterministic.
fn corpus_overlay_dirs() -> Vec<std::path::PathBuf> {
    let mut dirs = Vec::new();
    if let Some(home) = std::env::var_os("HOME") {
        let p = std::path::Path::new(&home).join(".laverna").join("corpus");
        if p.is_dir() {
            dirs.push(p);
        }
    }
    let cwd = std::path::Path::new("corpus");
    if cwd.is_dir() {
        dirs.push(cwd.to_path_buf());
    }
    dirs
}

/// Return the TOML contents of every `*.toml` file in the overlay corpus
/// directories, in deterministic order (home corpus first, then CWD corpus;
/// files sorted by path within each directory).
fn corpus_overlay_toml_contents() -> Vec<String> {
    let mut contents = Vec::new();
    for dir in corpus_overlay_dirs() {
        if let Ok(entries) = std::fs::read_dir(&dir) {
            let mut paths: Vec<_> = entries.flatten().map(|e| e.path()).collect();
            paths.sort();
            for path in paths {
                if path.extension().is_some_and(|e| e == "toml") {
                    if let Ok(c) = std::fs::read_to_string(&path) {
                        contents.push(c);
                    }
                }
            }
        }
    }
    contents
}

/// `laverna corpus export <dir>` — write the embedded corpus to TOML files.
///
/// With `--format cid-facts`, additionally emits `cid_facts.json`: a formula
/// registry Laverna's corpus exposes as a re-verifiable fact source for
/// Ł.AI · Gate (CID). Each entry carries a SHA-256 of the formula text so CID
/// can cite a deterministic, re-derivable fact (not a static lookup).
fn cmd_corpus_export(dir: &str, format: &str) {
    let path = std::path::Path::new(dir);
    if let Err(e) = std::fs::create_dir_all(path) {
        eprintln!("error: cannot create directory '{dir}': {e}");
        std::process::exit(2);
    }
    let formulas_path = path.join("formulas.toml");
    let mut formulas = String::new();
    formulas.push_str(FORMULAS_TOML);
    formulas.push('\n');
    formulas.push_str(NONMATH_TOML);
    if let Err(e) = std::fs::write(&formulas_path, &formulas) {
        eprintln!("error: cannot write {}: {e}", formulas_path.display());
        std::process::exit(2);
    }
    let entities_path = path.join("entities.toml");
    if let Err(e) = std::fs::write(&entities_path, ENTITIES_TOML) {
        eprintln!("error: cannot write {}: {e}", entities_path.display());
        std::process::exit(2);
    }
    let version_path = path.join("version.toml");
    if let Err(e) = std::fs::write(&version_path, CORPUS_VERSION_TOML) {
        eprintln!("error: cannot write {}: {e}", version_path.display());
        std::process::exit(2);
    }
    println!("exported formulas → {}", formulas_path.display());
    println!("exported entities → {}", entities_path.display());
    println!("exported version → {}", version_path.display());

    if format == "cid-facts" {
        let facts_path = path.join("cid_facts.json");
        match export_cid_facts() {
            Ok(json) => {
                if let Err(e) = std::fs::write(&facts_path, json) {
                    eprintln!("error: cannot write {}: {e}", facts_path.display());
                    std::process::exit(2);
                }
                println!("exported cid_facts.json → {}", facts_path.display());
            }
            Err(e) => {
                eprintln!("error: failed to build cid_facts.json: {e}");
                std::process::exit(2);
            }
        }
    }
}

/// Pure function: render the embedded formula corpus as a CID-consumable
/// fact-source JSON. Each formula becomes one entry with a content hash.
fn export_cid_facts() -> Result<String, String> {
    let registry = load_formula_registry();
    let mut entries: Vec<serde_json::Value> = Vec::new();
    for formula in registry.all() {
        let text = format!(
            "{}|{}|{}|{}",
            formula.id, formula.output, formula.expression, formula.description
        );
        let hash = laverna::digest::sha256_hex(text.as_bytes());
        entries.push(serde_json::json!({
            "id": formula.id,
            "domain": format!("{:?}", formula.domain),
            "formula_type": format!("{:?}", formula.formula_type),
            "inputs": formula.inputs,
            "output": formula.output,
            "expression": formula.expression,
            "description": formula.description,
            "zodiac": formula.zodiac,
            "hash": hash,
        }));
    }
    entries.sort_by(|a, b| {
        a.get("id")
            .and_then(|v| v.as_str())
            .cmp(&b.get("id").and_then(|v| v.as_str()))
    });
    let doc = serde_json::json!({
        "source": "laverna",
        "mark": "Ł.AI · Proof",
        "schema": "cid-facts/v1",
        "corpus_version": CORPUS_VERSION,
        "count": entries.len(),
        "facts": entries,
    });
    serde_json::to_string_pretty(&doc).map_err(|e| e.to_string())
}

/// `laverna corpus hash` — print the embedded corpus semver + content hash,
/// used to detect corpus drift across builds / community forks.
fn cmd_corpus_hash() {
    println!("version: {}", CORPUS_VERSION);
    println!("content_hash: {}", CORPUS_CONTENT_HASH);
}

/// `laverna corpus validate [dir]` — check Tanto parsability, graha refs,
/// non-empty descriptions, and duplicate ids.
fn cmd_corpus_validate(dir: Option<&str>) {
    let formulas_toml = corpus_formulas_toml(dir);
    let entities_toml = corpus_entities_toml(dir);

    let mut reg = FormulaRegistry::new();
    if let Err(e) = reg.load_from_toml_str(&formulas_toml) {
        eprintln!("error: formula corpus failed to load: {e}");
        std::process::exit(1);
    }

    let mut errors = Vec::new();
    let mut id_seen: std::collections::HashMap<String, usize> = std::collections::HashMap::new();
    for f in reg.all() {
        *id_seen.entry(f.id.clone()).or_insert(0) += 1;
        if f.expression.trim().is_empty() {
            errors.push(format!("formula '{}' has empty expression", f.id));
        } else if matches!(f.formula_type, FormulaType::Llm) {
            // LLM gates hold a prompt template in `expression`, not evaluable
            // arithmetic — skip Tanto syntax validation for them.
        } else if !is_expression_valid(&f.expression) {
            errors.push(format!(
                "formula '{}' expression is not valid Tanto syntax: {}",
                f.id, f.expression
            ));
        }
        if f.description.trim().is_empty() {
            errors.push(format!("formula '{}' has empty description", f.id));
        }
    }
    for (id, n) in &id_seen {
        if *n > 1 {
            errors.push(format!("formula id '{id}' appears {n} times (duplicate)"));
        }
    }

    let mut ent_reg = EntityRegistry::new();
    if let Err(e) = ent_reg.load_seeds_from_str(&entities_toml) {
        eprintln!("error: entity corpus failed to load: {e}");
        std::process::exit(1);
    }
    for id in ent_reg.list_seeds() {
        if let Some(seed) = ent_reg.get_seed_ref(id) {
            if seed.description.trim().is_empty() {
                errors.push(format!("entity '{id}' has empty description"));
            }
        }
    }

    if errors.is_empty() {
        println!(
            "✓ corpus valid: {} formulas, {} entities",
            reg.len(),
            ent_reg.seed_count()
        );
    } else {
        eprintln!("✗ corpus invalid ({} issue(s)):", errors.len());
        for e in &errors {
            eprintln!("  - {e}");
        }
        std::process::exit(1);
    }
}

/// `laverna corpus diff <a> <b>` — compare two exported corpus directories.
fn cmd_corpus_diff(a: &str, b: &str) {
    let a_formulas = corpus_formulas_toml(Some(a));
    let b_formulas = corpus_formulas_toml(Some(b));
    let a_entities = corpus_entities_toml(Some(a));
    let b_entities = corpus_entities_toml(Some(b));

    let mut reg_a = FormulaRegistry::new();
    let mut reg_b = FormulaRegistry::new();
    let _ = reg_a.load_from_toml_str(&a_formulas);
    let _ = reg_b.load_from_toml_str(&b_formulas);
    let mut ent_a = EntityRegistry::new();
    let mut ent_b = EntityRegistry::new();
    let _ = ent_a.load_seeds_from_str(&a_entities);
    let _ = ent_b.load_seeds_from_str(&b_entities);

    let mut added = Vec::new();
    let mut removed = Vec::new();
    let mut changed = Vec::new();

    for f in reg_b.all() {
        match reg_a.get(&f.id) {
            None => added.push(f.id.clone()),
            Some(prev) => {
                if prev.expression != f.expression
                    || prev.domain != f.domain
                    || prev.description != f.description
                {
                    changed.push(f.id.clone());
                }
            }
        }
    }
    for f in reg_a.all() {
        if reg_b.get(&f.id).is_none() {
            removed.push(f.id.clone());
        }
    }

    let mut e_added = Vec::new();
    let mut e_removed = Vec::new();
    for id in ent_b.list_seeds() {
        if ent_a.get_seed_ref(id).is_none() {
            e_added.push(id.to_string());
        }
    }
    for id in ent_a.list_seeds() {
        if ent_b.get_seed_ref(id).is_none() {
            e_removed.push(id.to_string());
        }
    }

    let value = serde_json::json!({
        "formulas": {"added": added, "removed": removed, "changed": changed},
        "entities": {"added": e_added, "removed": e_removed}
    });
    println!("{}", serde_json::to_string_pretty(&value).unwrap());
}

/// `laverna corpus graph [dir]` — emit a DOT graph of formula input→output deps.
fn cmd_corpus_graph(dir: Option<&str>) {
    let formulas_toml = corpus_formulas_toml(dir);
    let mut reg = FormulaRegistry::new();
    if let Err(e) = reg.load_from_toml_str(&formulas_toml) {
        eprintln!("error: formula corpus failed to load: {e}");
        std::process::exit(1);
    }

    let mut out = String::new();
    out.push_str("digraph formulas {\n");
    out.push_str("  rankdir=LR;\n");
    out.push_str("  node [shape=box];\n");
    for f in reg.all() {
        let label = f.expression.replace('"', "'");
        out.push_str(&format!(
            "  \"{}\" [label=\"{}\\n{}\"];\n",
            f.id, f.id, label
        ));
        // Edge from each input symbol to this formula (if the symbol is itself a formula id).
        for input in &f.inputs {
            if reg.get(input).is_some() {
                out.push_str(&format!("  \"{}\" -> \"{}\";\n", input, f.id));
            }
        }
        // Explicit `relations` edges (dashed) declared in the formula schema.
        for rel in &f.relations {
            if reg.get(rel).is_some() {
                out.push_str(&format!(
                    "  \"{}\" -> \"{}\" [style=dashed,label=\"rel\"];\n",
                    rel, f.id
                ));
            }
        }
    }
    out.push_str("}\n");
    print!("{out}");
}

/// `laverna corpus lint [dir]` — deeper corpus checks than `validate`:
/// flags expressions that reference identifiers not declared in the formula's
/// `inputs` (and not known constants / other formula ids), and formulas that
/// carry no graha/zodiac tag. Warnings are non-fatal (exit 0), so lint can run
/// in CI as an advisory.
fn cmd_corpus_lint(dir: Option<&str>) {
    let formulas_toml = corpus_formulas_toml(dir);
    let entities_toml = corpus_entities_toml(dir);

    let mut reg = FormulaRegistry::new();
    if let Err(e) = reg.load_from_toml_str(&formulas_toml) {
        eprintln!("error: formula corpus failed to load: {e}");
        std::process::exit(1);
    }

    // Known constants from the default Tanto environment (e.g. pi, e, c, G).
    let env = create_env();
    let constants: std::collections::HashSet<&str> = env.keys().map(|s| s.as_str()).collect();
    // Every formula id — expressions may legitimately reference another formula.
    let formula_ids: std::collections::HashSet<String> =
        reg.all().iter().map(|f| f.id.clone()).collect();

    let mut warnings = Vec::new();
    for f in reg.all() {
        if matches!(f.formula_type, FormulaType::Llm) {
            continue;
        }
        let declared: std::collections::HashSet<&str> =
            f.inputs.iter().map(|s| s.as_str()).collect();
        for ident in extract_identifiers(&f.expression) {
            if declared.contains(ident.as_str())
                || constants.contains(ident.as_str())
                || formula_ids.contains(&ident)
            {
                continue;
            }
            warnings.push(format!(
                "formula '{}' references undeclared variable '{}'",
                f.id, ident
            ));
        }
        if f.zodiac.is_empty() {
            warnings.push(format!(
                "formula '{}' has no graha/zodiac tag (domain: {:?})",
                f.id, f.domain
            ));
        }
    }

    let mut ent_reg = EntityRegistry::new();
    if let Err(e) = ent_reg.load_seeds_from_str(&entities_toml) {
        eprintln!("error: entity corpus failed to load: {e}");
        std::process::exit(1);
    }
    for id in ent_reg.list_seeds() {
        if let Some(seed) = ent_reg.get_seed_ref(id) {
            if seed.description.trim().is_empty() {
                warnings.push(format!("entity '{id}' has empty description"));
            }
        }
    }

    if warnings.is_empty() {
        println!(
            "✓ corpus lint clean: {} formulas, {} entities",
            reg.len(),
            ent_reg.seed_count()
        );
    } else {
        eprintln!("⚠ corpus lint ({} warning(s)):", warnings.len());
        for w in &warnings {
            eprintln!("  - {w}");
        }
    }
}

/// Current timestamp as seconds since Unix epoch (best-effort, no extra deps).
fn chrono_now() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    match SystemTime::now().duration_since(UNIX_EPOCH) {
        Ok(d) => format!("{}", d.as_secs()),
        Err(_) => String::new(),
    }
}

/// Render `solve` as text or JSON.
fn print_solve(result: &SolveResult, verbose: bool, explain: bool, format: OutputFormat) {
    if format == OutputFormat::Json {
        let value = solve_to_json(result);
        println!("{}", serde_json::to_string(&value).unwrap());
        return;
    }

    println!("intent: {}", result.intent);
    println!("domain: {}", result.domain);
    if !result.numerical.is_empty() {
        println!("numerical: {:?}", result.numerical);
    }

    println!();
    println!(
        "descent: {:.0}% resolution, {:.2}/6 avg depth, {:.0}% NAND",
        result.matrix.resolution_score * 100.0,
        result.matrix.average_depth,
        result.matrix.nand_completeness() * 100.0,
    );

    for token in &result.matrix.tokens {
        let depth = token.settled_layer.depth();
        let layer = token.settled_layer.name();
        print!("  \"{}\" → {layer} (d{depth})", token.text);
        if !token.domains.is_empty() {
            let domains: Vec<_> = token.domains.iter().map(|d| format!("{d:?}")).collect();
            print!(", domains: [{}]", domains.join(", "));
        }
        if !token.formulas.is_empty() {
            print!(", formulas: {}", token.formulas.len());
        }
        if let Some(ref entity) = token.entity {
            print!(", entity: {entity}");
        }
        if let Some(ref formal) = token.formal_expression {
            print!(", formal: \"{formal}\"");
        }
        if token.is_absolute {
            print!(", NAND: absolute");
        }
        println!();
    }

    // Tanto math evaluation for formal expressions
    if !result.tanto_evals.is_empty() {
        println!();
        println!("tanto evaluations:");
        for (token, expr, val) in &result.tanto_evals {
            match val {
                Some(v) => println!("  {token} ({expr}) = {v:.4}"),
                None => println!("  {token} ({expr}) = error: evaluation failed"),
            }
        }
    }

    // Numerical evaluation
    if !result.num_exprs.is_empty() {
        println!();
        println!("numerical expressions:");
        for e in &result.num_exprs {
            match (e.lhs_value, e.stated_rhs, e.matches) {
                (Some(l), Some(r), Some(m)) => println!(
                    "  {} = {l:.4}  (stated RHS {r}: {})",
                    e.expr,
                    if m { "✓ match" } else { "✗ mismatch" }
                ),
                (Some(l), None, _) => println!("  {} = {l:.4}", e.expr),
                _ => println!("  {}: could not evaluate", e.expr),
            }
        }
    } else if result.numerical.len() >= 2 {
        println!();
        println!(
            "  (no operator expression present; scalars: {:?})",
            result.numerical
        );
    }

    // Richer trace: per-token graha decomposition (T46#4)
    if explain {
        println!();
        println!("graha decomposition:");
        for token in &result.matrix.tokens {
            let g = laverna::strategy::dominant_graha_display(token).map(|d| d.name().to_string());
            println!(
                "  \"{}\" → {}",
                token.text,
                g.unwrap_or_else(|| "—".to_string())
            );
        }
    }

    // Provenance (verbose or explain)
    if verbose || explain {
        println!();
        println!("provenance:");
        for (token, steps) in &result.provenance {
            println!("  \"{token}\" ({} steps):", steps.len());
            for (i, step) in steps.iter().enumerate() {
                match step {
                    ProvenanceStep::DomainClassification {
                        domain,
                        keyword,
                        confidence,
                    } => {
                        println!(
                            "    {}. DomainClassification: domain={keyword}→{domain}, conf={confidence:.1}",
                            i + 1
                        );
                    }
                    ProvenanceStep::FormulaMatch {
                        formula_id,
                        domain,
                        inputs,
                        output,
                    } => {
                        println!(
                            "    {}. FormulaMatch: {formula_id} [{domain}] {:?}→{output}",
                            i + 1,
                            inputs.as_slice()
                        );
                    }
                    ProvenanceStep::EntityMatch { entity_id, domain } => {
                        println!("    {}. EntityMatch: {entity_id} [{domain}]", i + 1);
                    }
                    ProvenanceStep::Unification {
                        formula_id,
                        entity_id,
                        bound_inputs,
                        ..
                    } => {
                        println!(
                            "    {}. Unification: formula={formula_id} entity={entity_id} bound={bound_inputs:?}",
                            i + 1
                        );
                    }
                    ProvenanceStep::FormalExpression { token, expression } => {
                        println!("    {}. FormalExpression: {token}=\"{expression}\"", i + 1);
                    }
                    ProvenanceStep::NandEvaluation {
                        gate,
                        inputs,
                        output,
                    } => {
                        println!("    {}. NandEvaluation: {gate}({inputs:?})={output}", i + 1);
                    }
                }
            }
        }
    }

    // Dominant domain summary
    if !result.matrix.dominant_domains.is_empty() {
        let domains: Vec<_> = result
            .matrix
            .dominant_domains
            .iter()
            .map(|d| format!("{d:?}"))
            .collect();
        println!();
        println!("dominant: [{}]", domains.join(", "));
    }
}

/// Build the JSON rendering of a `solve` result (self-describing for LLM callers).
fn solve_to_json(result: &SolveResult) -> Value {
    let mut tokens = serde_json::to_value(&result.matrix.tokens).unwrap();
    if let Value::Array(arr) = &mut tokens {
        for (i, tok_val) in arr.iter_mut().enumerate() {
            if let Some(tok) = result.matrix.tokens.get(i) {
                let graha =
                    laverna::strategy::dominant_graha_display(tok).map(|d| d.name().to_string());
                if let Value::Object(o) = tok_val {
                    o.insert(
                        "dominant_graha".to_string(),
                        serde_json::to_value(&graha).unwrap(),
                    );
                }
            }
        }
    }
    let tanto: Vec<Value> = result
        .tanto_evals
        .iter()
        .map(|(tok, expr, val)| serde_json::json!({"token": tok, "expression": expr, "value": val}))
        .collect();
    let num_exprs: Vec<Value> = result
        .num_exprs
        .iter()
        .map(|e| {
            serde_json::json!({
                "expression": e.expr,
                "lhs_value": e.lhs_value,
                "stated_rhs": e.stated_rhs,
                "matches": e.matches
            })
        })
        .collect();
    let provenance: Vec<Value> = result
        .provenance
        .iter()
        .map(|(tok, steps)| serde_json::json!({"token": tok, "steps": steps}))
        .collect();
    serde_json::json!({
        "query": result.query,
        "intent": result.intent,
        "domain": result.domain,
        "numerical": result.numerical,
        "descent": {
            "resolution_score": result.matrix.resolution_score * 100.0,
            "average_depth": result.matrix.average_depth,
            "nand_completeness": result.matrix.nand_completeness()
        },
        "tokens": tokens,
        "tanto_evaluations": tanto,
        "numerical_expressions": num_exprs,
        "provenance": provenance,
        "dominant_domains": result.matrix.dominant_domains
    })
}

/// Batch mode: read queries from stdin (JSONL `{"query": "..."}` or one per line)
/// and emit one JSON object per line (JSONL) — amortizes the registry load.
fn cmd_solve_batch(_verbose: bool, _explain: bool) {
    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut out = stdout.lock();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => break,
        };
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        let query: String = if let Ok(v) = serde_json::from_str::<Value>(line) {
            v.get("query")
                .and_then(|q| q.as_str())
                .map(|s| s.to_string())
                .unwrap_or_else(|| line.to_string())
        } else {
            line.to_string()
        };
        let result = run_solve(&query);
        let value = solve_to_json(&result);
        let _ = writeln!(out, "{}", serde_json::to_string(&value).unwrap());
    }
}

// ─── route Command (reverse routing) ──────────────────────────────────────────

/// Build the descent matrix for a routing query using the same deterministic
/// pipeline as `cmd_solve`. The formula registry is accepted pre-loaded so the
/// caller can reuse it for IDF-style token specificity (T55) without re-parsing
/// the corpus per query.
fn build_route_matrix_with(formula_reg: FormulaRegistry, query: &str) -> SettlingMatrix {
    let entity_reg = load_entity_registry();
    let forms = load_shikai_forms();
    let events = load_events();
    let descent_engine = DescentEngine::new(formula_reg, entity_reg, forms, events);
    descent_engine.descend(query)
}

/// Corpus specificity weight for a resolved token (T55). Rare tokens (few
/// formulas mention them) carry more routing signal; common words carry less.
/// Pure function of the token text + the loaded corpus — identical queries get
/// identical weights. Document frequency comes from the registry's word index
/// (built by `finalize()` in `load_formula_registry`).
fn token_specificity(token: &str, formula_reg: &FormulaRegistry) -> f64 {
    let doc_freq = formula_reg.search(token).len();
    // Smoothed inverse document frequency in (0, 1]: df=0 → 1.0, larger df → smaller.
    1.0 / (1.0 + (doc_freq as f64).ln_1p())
}

/// Reverse-route result — rendered as text or JSON without recomputation.
struct RouteResult {
    query: String,
    report: StrategyReport,
    /// Per-token dominant graha force as `(symbol, name)`, or `None`.
    decomposition: Vec<(String, Option<(String, String)>)>,
}

/// Reverse-route a query to a strategy: descent → pure token→graha resolution
/// → synthesized action framework. Mirrors `cmd_solve`'s descent setup so the
/// strategy is grounded in the same deterministic pipeline. Token→graha is a
/// PURE function of the token text (T54): no neighbor-domain inheritance, and
/// stopwords/unresolved words carry no vote (T55).
fn run_route(query: &str) -> RouteResult {
    let mut formula_reg = load_formula_registry();
    // Build the word index once so IDF-specificity lookups (T55) hit the O(1)
    // fast path. Deferred to the route path only — `solve`/`build` don't need
    // it, so the eager fold stays off their hot paths (PERF).
    formula_reg.finalize();
    let matrix = build_route_matrix_with(formula_reg.clone(), query);
    let forces: Vec<(String, TokenForce)> = matrix
        .tokens
        .iter()
        .map(|t| {
            let specificity = token_specificity(&t.text, &formula_reg);
            (t.text.clone(), classify_route_token(t, specificity))
        })
        .collect();
    let report: StrategyReport = synthesize_strategy(query, &forces);
    // Decomposition mirrors the SAME pure classification used for synthesis, so
    // the per-token trace never shows a stopword or neighbor-inherited graha
    // (T54/T55): stopwords are flagged, everything else shows its resolved graha.
    let decomposition = forces
        .iter()
        .map(|(text, force)| {
            let entry = match force {
                TokenForce::Resolved { graha, .. } => {
                    Some((graha.symbol().to_string(), graha.name().to_string()))
                }
                TokenForce::Stopword => Some(("—".to_string(), "stopword".to_string())),
                TokenForce::Unresolved => None,
            };
            (text.clone(), entry)
        })
        .collect();
    RouteResult {
        query: query.to_string(),
        report,
        decomposition,
    }
}

/// Render one graha `Domain` (or null) as a JSON object.
fn domain_value(g: Option<Domain>) -> Value {
    match g {
        Some(d) => serde_json::json!({
            "symbol": d.symbol(),
            "name": d.name(),
            "full_name": d.full_name(),
            "archetype": d.archetype(),
            "index": d.index()
        }),
        None => Value::Null,
    }
}

/// Render `route` as text or JSON.
fn print_route(result: &RouteResult, verbose: bool, explain: bool, format: OutputFormat) {
    if format == OutputFormat::Json {
        println!("{}", serde_json::to_string(&route_to_json(result)).unwrap());
        return;
    }

    println!("{}", result.report.format());

    if verbose || explain {
        println!();
        println!("decomposition (each token → dominant force):");
        for (token, g) in &result.decomposition {
            match g {
                Some((sym, name)) => println!("  \"{token}\" → {sym} ({name})"),
                None => println!("  \"{token}\" → (no graha force)"),
            }
        }
    }
}

/// Build the JSON rendering of a `route` result.
fn route_to_json(result: &RouteResult) -> Value {
    let forces: Vec<Value> = result
        .report
        .ranked
        .iter()
        .map(|(g, weight, share)| {
            serde_json::json!({
                "symbol": g.symbol(),
                "name": g.name(),
                "full_name": g.full_name(),
                "archetype": g.archetype(),
                "index": g.index(),
                "weight": weight,
                "share": share
            })
        })
        .collect();
    let decomposition: Vec<Value> = result
        .decomposition
        .iter()
        .map(|(token, g)| {
            serde_json::json!({"token": token, "symbol": g.as_ref().map(|(s, _)| s), "name": g.as_ref().map(|(_, n)| n)})
        })
        .collect();
    serde_json::json!({
        "query": result.query,
        "forces": forces,
        "primary": domain_value(result.report.primary),
        "secondary": domain_value(result.report.secondary),
        "tertiary": domain_value(result.report.tertiary),
        "unresolved": result.report.unresolved,
        "stopwords": result.report.stopwords,
        "warning": result.report.warning,
        "decomposition": decomposition
    })
}

/// A known repo's assimilation profile: the descriptor drives the descent
