#[cfg(test)]
mod t36_tests {
    use super::*;

    #[test]
    fn extracts_operator_expression_with_precedence() {
        // "2 + 3 * 4" must evaluate to 14, not naive (2+3)=5 then (3*4)...
        let expr = extract_arithmetic_expression("what is 2 + 3 * 4?").expect("expr");
        let env = create_env();
        let val = evaluate_expr(&expr, &env).expect("eval");
        assert!((val - 14.0).abs() < 1e-9, "expected 14, got {val}");
    }

    #[test]
    fn extracts_equation_and_splits_lhs() {
        let expr = extract_arithmetic_expression("verify 2 + 3 = 5").expect("expr");
        assert!(expr.contains('='));
        let env = create_env();
        let eq = expr.find('=').unwrap();
        let left_operand = &expr[..eq];
        let val = evaluate_expr(left_operand, &env).expect("eval left_operand");
        assert!((val - 5.0).abs() < 1e-9, "expected 5, got {val}");
    }

    #[test]
    fn modulo_keeps_first_operand() {
        // T42 regression: "%" must not drop the left operand.
        // "10 % 3 = 1" must evaluate to 1.0 and match stated RHS.
        let expr = extract_arithmetic_expression("10 % 3 = 1").expect("expr");
        assert!(expr.contains('%'), "expr dropped modulo: {expr:?}");
        let env = create_env();
        let eq = expr.find('=').unwrap();
        let left_operand = &expr[..eq];
        let val = evaluate_expr(left_operand, &env).expect("eval left_operand");
        assert!((val - 1.0).abs() < 1e-9, "expected 1, got {val}");
        let right_operand: f64 = expr[eq + 1..].trim().parse().unwrap();
        assert!(
            (val - right_operand).abs() < 1e-9,
            "left_operand {val} != right_operand {right_operand}"
        );
    }

    #[test]
    fn no_arithmetic_returns_none() {
        assert!(extract_arithmetic_expression("the cat sat on the mat").is_none());
    }

    #[test]
    fn strips_trailing_operator() {
        let expr = extract_arithmetic_expression("compute 2 + 3 =").expect("expr");
        assert!(!expr.ends_with('='), "expr was {expr:?}");
        let env = create_env();
        assert!((evaluate_expr(&expr, &env).unwrap() - 5.0).abs() < 1e-9);
    }
}

#[cfg(test)]
mod proof_tests {
    use super::*;

    #[test]
    fn proof_embedds_corpus_version_and_hash() {
        // Part 2.6: every proof object must pin the corpus it was computed
        // against (T35 embedded corpus) so a verifier can reject proofs that
        // silently drift the knowledge base.
        let result = run_solve("दशम भाव मे बुध");
        let proof = build_proof_object(&result, false);
        let corpus = proof
            .get("corpus")
            .expect("proof must contain corpus block");
        assert_eq!(corpus["version"], CORPUS_VERSION);
        assert_eq!(corpus["content_hash"], CORPUS_CONTENT_HASH);
        assert!(!CORPUS_CONTENT_HASH.is_empty());
    }

    #[test]
    fn proof_digest_is_stable_without_timestamp() {
        // T53: with timestamp off, two proofs of the same query are byte-identical.
        let result = run_solve("दशम भाव मे बुध");
        let a = build_proof_object(&result, false);
        let b = build_proof_object(&result, false);
        assert_eq!(a.to_string(), b.to_string());
        assert_eq!(
            a["digest"]["value"].as_str().unwrap(),
            b["digest"]["value"].as_str().unwrap()
        );
    }

    #[test]
    fn verify_recomputation_matches_recorded_proof() {
        // Recompute path used by `laverna verify`: rebuild the canonical payload
        // from the recorded query and confirm it equals the recorded payload.
        let result = run_solve("दशम भाव मे बुध");
        let proof = build_proof_object(&result, false);
        let recorded = proof_payload_view(&proof);
        let recomputed = build_proof_payload(&run_solve(proof["query"].as_str().unwrap()));
        assert_eq!(recorded, recomputed);
        assert_eq!(proof_digest(&recorded), proof_digest(&recomputed));
    }
}

// ─── Gate Command Handlers ──────────────────────────────────────────────────

fn cmd_gate_validate(text: &str, context: &str, domain: Option<&str>, format: OutputFormat) {
    use cid::inference::{InferenceEngine, ValidationRequest};
    let mut engine = InferenceEngine::new();
    let mut request = ValidationRequest::new(text, context);
    if let Some(d) = domain {
        request = request.with_domain(d);
    }
    match engine.validate(request) {
        Ok(result) => {
            if format == OutputFormat::Json {
                let value = serde_json::json!({
                    "validated_text": result.validated_text,
                    "original_text": result.original_text,
                    "confidence": result.confidence,
                    "passed": result.passed,
                    "fix_count": result.fix_count(),
                    "state": format!("{:?}", result.state),
                    "cost_usd": result.cost_usd,
                });
                println!("{}", serde_json::to_string(&value).unwrap());
            } else {
                println!("Validated: {}", result.validated_text);
                println!("Confidence: {:.4}", result.confidence);
                println!("Passed: {}", result.passed);
                println!("Fixes: {}", result.fix_count());
                println!("State: {:?}", result.state);
                println!("Cost: ${:.6}", result.cost_usd);
            }
        }
        Err(e) => {
            if format == OutputFormat::Json {
                let value = serde_json::json!({ "error": e.to_string() });
                eprintln!("{}", serde_json::to_string(&value).unwrap());
            } else {
                eprintln!("Error: {}", e);
            }
            std::process::exit(1);
        }
    }
}

fn cmd_gate_fix(text: &str, context: &str, format: OutputFormat) {
    use cid::inference::InferenceEngine;
    let mut engine = InferenceEngine::new();
    let (fixed, fixes) = engine.fix(text, context);
    if format == OutputFormat::Json {
        let fix_objs: Vec<serde_json::Value> = fixes
            .iter()
            .map(|f| {
                serde_json::json!({
                    "original": f.original,
                    "fixed": f.fixed,
                    "reason": f.reason,
                })
            })
            .collect();
        let value = serde_json::json!({
            "original": text,
            "fixed": fixed,
            "fixes": fix_objs,
        });
        println!("{}", serde_json::to_string(&value).unwrap());
    } else {
        println!("Original: {}", text);
        println!("Fixed: {}", fixed);
        if !fixes.is_empty() {
            println!("Fixes:");
            for fix in &fixes {
                println!("  {} -> {} ({})", fix.original, fix.fixed, fix.reason);
            }
        }
    }
}

fn cmd_gate_compress(text: &str, level: Option<&str>) {
    use cid::inference::{CompressionLevel, PromptCompressor};
    let lvl = match level {
        Some("light") => CompressionLevel::Light,
        Some("aggressive") => CompressionLevel::Aggressive,
        _ => CompressionLevel::Medium,
    };
    let compressor = PromptCompressor::new(lvl);
    let (compressed, stats) = compressor.compress(text);
    println!("Compressed: {}", compressed);
    println!("Original tokens: {}", stats.original_tokens);
    println!("Compressed tokens: {}", stats.compressed_tokens);
    println!(
        "Saved: {} tokens ({:.1}%)",
        stats.saved_tokens, stats.saved_percent
    );
}

fn cmd_gate_score(text: &str, context: Option<&str>, format: OutputFormat) {
    use cid::inference::ResponseScorer;
    let scorer = ResponseScorer::new();
    let ctx = context.unwrap_or("general");
    let report = scorer.score(text, ctx);
    if format == OutputFormat::Json {
        let issue_objs: Vec<serde_json::Value> = report
            .issues
            .iter()
            .map(|issue| {
                serde_json::json!({
                    "category": format!("{:?}", issue.category),
                    "description": issue.description,
                    "severity": format!("{:?}", issue.severity),
                    "confidence": issue.confidence,
                })
            })
            .collect();
        let value = serde_json::json!({
            "overall_score": report.overall_score,
            "confidence": report.confidence,
            "action": format!("{:?}", report.action),
            "issues": issue_objs,
        });
        println!("{}", serde_json::to_string(&value).unwrap());
    } else {
        println!("Quality Score: {:.2}", report.overall_score);
        println!("Confidence: {:.2}", report.confidence);
        println!("Action: {:?}", report.action);
        if !report.issues.is_empty() {
            println!("Issues:");
            for issue in &report.issues {
                println!(
                    "  [{:?}] {}: {}",
                    issue.severity, issue.category, issue.description
                );
            }
        }
    }
}

