fn cmd_gate_repl() {
    use cid::core::pin::PinField;
    use cid::economy::tray::BallEconomy;
    use cid::kb::facts::KnowledgeBase;
    use cid::state::machine::StateMachine;

    struct ReplState {
        state_machine: StateMachine,
        economy: BallEconomy,
        pin_field: PinField,
        kb: KnowledgeBase,
    }

    impl ReplState {
        fn new() -> Self {
            Self {
                state_machine: StateMachine::new(),
                economy: BallEconomy::new(100),
                pin_field: PinField::default(),
                kb: KnowledgeBase::default(),
            }
        }

        fn show_help(&self) -> String {
            "L.ai · Gate REPL (Ctrl-D to exit)\n\n\
             Commands:\n  \
               gate <token> <context>       Validate a token\n  \
               beam <token1,token2> <ctx>   Validate multiple tokens\n  \
               validate <text> <context>    Validate via inference API\n  \
               fix <text> --- <context>     Auto-fix mode\n  \
               state                        Show current state\n  \
               pins                         Show pin field\n  \
               economy                      Show ball economy\n  \
               compress <text> [level]      Compress prompt\n  \
               score <text>                 Score response quality\n  \
               kb list | kb lookup <name>   Knowledge base\n  \
               tanto <subcmd> [args]        Tanto compute engine\n  \
               test                         Run self-test\n  \
               help                         Show this help\n"
                .to_string()
        }

        fn process_line(&mut self, line: &str) -> String {
            let parts: Vec<&str> = line.splitn(3, ' ').collect();
            match parts[0] {
                "help" | "?" => self.show_help(),
                "state" => format!("State: {:?}", self.state_machine.current()),
                "economy" | "econ" => format!(
                    "Economy:\n  Tray: {}\n  Spent: {}\n  Won: {}\n  Cost: ${:.6}\n  ROI: {:.1}%",
                    self.economy.balance(),
                    self.economy.total_spent(),
                    self.economy.total_won(),
                    self.economy.total_cost_usd(),
                    self.economy.roi()
                ),
                "pins" => {
                    let mut out = String::from("Pin Field:\n");
                    for pin in &self.pin_field.pins {
                        let status = if pin.enabled { "ENABLED" } else { "DISABLED" };
                        out.push_str(&format!(
                            "  {:?}: threshold={:.2}, cost={:.6}, status={}\n",
                            pin.gate, pin.threshold, pin.cost, status
                        ));
                    }
                    out
                }
                "kb" => {
                    if parts.len() < 2 {
                        return "Usage: kb list | kb lookup <name>".to_string();
                    }
                    match parts[1] {
                        "list" => {
                            let mut out = String::from("Knowledge Base:\n");
                            for fact in self.kb.list_facts() {
                                out.push_str(&format!(
                                    "  {} = {} {}\n",
                                    fact.name, fact.value, fact.unit
                                ));
                            }
                            out
                        }
                        "lookup" => {
                            if parts.len() < 3 {
                                return "Usage: kb lookup <name>".to_string();
                            }
                            match self.kb.lookup(parts[2]) {
                                Some(fact) => format!(
                                    "{} = {} {} [{}]",
                                    fact.name, fact.value, fact.unit, fact.source
                                ),
                                None => format!("Fact '{}' not found", parts[2]),
                            }
                        }
                        _ => "Usage: kb list | kb lookup <name>".to_string(),
                    }
                }
                "test" => {
                    let mut out = String::from("=== CID SELF-TEST ===\n");
                    out.push_str("Math test: PASS (placeholder)\n");
                    out.push_str("Logic test: PASS (placeholder)\n");
                    out.push_str("Fact test: PASS (placeholder)\n");
                    out.push_str("=== TESTS COMPLETE ===\n");
                    out
                }
                "exit" | "quit" | "q" => {
                    std::process::exit(0);
                }
                "validate" => {
                    if parts.len() < 2 {
                        "Usage: validate <text> [context]".to_string()
                    } else {
                        let text = parts[1];
                        let ctx = if parts.len() > 2 { parts[2] } else { "" };
                        use cid::inference::{InferenceEngine, ValidationRequest};
                        let mut engine = InferenceEngine::new();
                        let request = ValidationRequest::new(text, ctx);
                        match engine.validate(request) {
                            Ok(result) => format!(
                                "Validated: {}\nConfidence: {:.4}\nPassed: {}",
                                result.validated_text, result.confidence, result.passed
                            ),
                            Err(e) => format!("Error: {}", e),
                        }
                    }
                }
                "fix" => {
                    if parts.len() < 2 {
                        "Usage: fix <text> [context]".to_string()
                    } else {
                        let text = parts[1];
                        let ctx = if parts.len() > 2 { parts[2] } else { "" };
                        use cid::inference::InferenceEngine;
                        let mut engine = InferenceEngine::new();
                        let (fixed, fixes) = engine.fix(text, ctx);
                        if fixes.is_empty() {
                            format!("Already valid: {}", text)
                        } else {
                            let mut out = format!("Original: {}\nFixed: {}", text, fixed);
                            for fix in &fixes {
                                out.push_str(&format!(
                                    "\n  {} -> {} ({})",
                                    fix.original, fix.fixed, fix.reason
                                ));
                            }
                            out
                        }
                    }
                }
                "compress" => {
                    if parts.len() < 2 {
                        "Usage: compress <text> [light|medium|aggressive]".to_string()
                    } else {
                        let text = parts[1];
                        let level_str = if parts.len() > 2 { parts[2] } else { "medium" };
                        use cid::inference::{CompressionLevel, PromptCompressor};
                        let lvl = match level_str {
                            "light" => CompressionLevel::Light,
                            "aggressive" => CompressionLevel::Aggressive,
                            _ => CompressionLevel::Medium,
                        };
                        let compressor = PromptCompressor::new(lvl);
                        let (compressed, stats) = compressor.compress(text);
                        format!(
                            "Compressed: {}\nOriginal tokens: {}\nCompressed tokens: {}\nSaved: {} tokens ({:.1}%)",
                            compressed, stats.original_tokens, stats.compressed_tokens, stats.saved_tokens, stats.saved_percent
                        )
                    }
                }
                "score" => {
                    if parts.len() < 2 {
                        "Usage: score <text> [context]".to_string()
                    } else {
                        let text = parts[1];
                        let ctx = if parts.len() > 2 { parts[2] } else { "general" };
                        use cid::inference::ResponseScorer;
                        let scorer = ResponseScorer::new();
                        let report = scorer.score(text, ctx);
                        format!(
                            "Score: {:.2}\nConfidence: {:.2}\nAction: {:?}\nIssues: {}",
                            report.overall_score,
                            report.confidence,
                            report.action,
                            report.issues.len()
                        )
                    }
                }
                "tanto" => {
                    if parts.len() < 2 {
                        "Usage: tanto eval <expr> | tanto convert <val> <from> <to> | tanto formula <name> [args...]".to_string()
                    } else {
                        match parts[1] {
                            "eval" => {
                                if parts.len() < 3 {
                                    "Usage: tanto eval <expression>".to_string()
                                } else {
                                    let expr = if parts.len() > 3 {
                                        parts[2..].join(" ")
                                    } else {
                                        parts[2].to_string()
                                    };
                                    let env = &mut cid::tanto::TantoEnv::new();
                                    match cid::tanto::evaluate_nl(&expr, env) {
                                        Some(val) => {
                                            format!("= {}", cid::tanto::math::format_f64(val))
                                        }
                                        None => format!("Error: cannot evaluate '{}'", expr),
                                    }
                                }
                            }
                            "convert" => {
                                if parts.len() < 5 {
                                    "Usage: tanto convert <value> <from_unit> <to_unit>".to_string()
                                } else {
                                    let val: f64 = match parts[2].parse() {
                                        Ok(v) => v,
                                        Err(_) => {
                                            return format!("Error: '{}' is not a number", parts[2])
                                        }
                                    };
                                    let query = format!("{} {} {}", val, parts[3], parts[4]);
                                    match cid::tanto::convert::convert(&query) {
                                        Some(cr) => format!(
                                            "= {} {} (from {} to {})",
                                            cid::tanto::math::format_f64(cr.value),
                                            cr.to,
                                            cr.from,
                                            cr.to
                                        ),
                                        None => format!(
                                            "Error: unknown conversion '{} {} {}'",
                                            val, parts[3], parts[4]
                                        ),
                                    }
                                }
                            }
                            "formula" => {
                                if parts.len() < 3 {
                                    "Usage: tanto formula <name> [args...]".to_string()
                                } else {
                                    let rest = parts[2..].join(" ");
                                    match cid::tanto::formulas::compute_formula(&rest) {
                                        Some(fr) => format!(
                                            "{} = {}  [{}]",
                                            fr.name,
                                            cid::tanto::math::format_f64(fr.result),
                                            fr.formula
                                        ),
                                        None => format!("Error: unknown formula '{}'", rest),
                                    }
                                }
                            }
                            _ => format!(
                                "Unknown tanto subcommand: '{}'. Use eval, convert, or formula.",
                                parts[1]
                            ),
                        }
                    }
                }
                _ => format!("Unknown command: {}. Try 'help'.", parts[0]),
            }
        }
    }

    let mut state = ReplState::new();
    let stdin = io::stdin();
    let reader = BufReader::new(stdin.lock());
    let mut stdout = io::stdout();

    for line in reader.lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => break,
        };
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        let result = state.process_line(line);
        let _ = stdout.write_all(result.as_bytes());
        let _ = stdout.write_all(b"\n");
        let _ = stdout.flush();
    }
}

// ─── Tanto Command Handlers ─────────────────────────────────────────────────

fn cmd_tanto_eval(expression: &str) {
    let env = &mut cid::tanto::TantoEnv::new();
    match cid::tanto::evaluate_nl(expression, env) {
        Some(val) => println!("= {}", cid::tanto::math::format_f64(val)),
        None => {
            eprintln!("Error: cannot evaluate '{}'", expression);
            std::process::exit(1);
        }
    }
}

fn cmd_tanto_convert(value: f64, from: &str, to: &str) {
    let query = format!("{} {} {}", value, from, to);
    match cid::tanto::convert::convert(&query) {
        Some(cr) => println!(
            "= {} {} (from {} to {})",
            cid::tanto::math::format_f64(cr.value),
            cr.to,
            cr.from,
            cr.to
        ),
        None => {
            eprintln!("Error: unknown conversion '{} {} {}'", value, from, to);
            std::process::exit(1);
        }
    }
}

fn cmd_tanto_formula(name: &str, args: &[String]) {
    let query = if args.is_empty() {
        name.to_string()
    } else {
        format!("{} {}", name, args.join(" "))
    };
    match cid::tanto::formulas::compute_formula(&query) {
        Some(fr) => println!(
            "{} = {}  [{}]",
            fr.name,
            cid::tanto::math::format_f64(fr.result),
            fr.formula
        ),
        None => match eval_corpus_formula(name, args) {
            Some((result, expr)) => println!(
                "{} = {}  [{}]",
                name,
                cid::tanto::math::format_f64(result),
                expr
            ),
            None => {
                eprintln!("Error: unknown formula '{}'", query);
                std::process::exit(1);
            }
        },
    }
}

/// Evaluate a named corpus formula (proof `FormulaRegistry`) by binding the
/// provided positional args to its declared `inputs` in order. Falls back here
/// when the gate tanto formula set has no match (multi-arg corpus formulas such
/// as `add 2 3`, `electrical_power 12 2`, `annuity_value 100 0.05 10`).
fn eval_corpus_formula(name: &str, args: &[String]) -> Option<(f64, String)> {
    let reg = load_formula_registry();
    let formula = reg.get(name)?;
    if args.len() != formula.inputs.len() {
        return None;
    }
    let mut env = create_env();
    for (input, arg) in formula.inputs.iter().zip(args.iter()) {
        let val = arg.parse::<f64>().ok()?;
        env.insert(input.clone(), val);
    }
    let result = evaluate_expr(&formula.expression, &env)?;
    Some((result, formula.expression.clone()))
}

